     params.log?.(`slack: webhook path ${normalizedPath} already registered${suffix}`);
     return () => {};
   }
-  slackHttpRoutes.set(normalizedPath, params.handler);
+  routes.set(normalizedPath, params.handler);
   return () => {
-    slackHttpRoutes.delete(normalizedPath);
